// Extract and normalize lead data from webhook
const lead = $input.first().json;

const nome = (lead.nome || '').split(' ')[0];
const empresa = lead.empresa || '';
const setor = lead.setor || 'Outro';
const cargo = lead.cargo || '';
const tier = lead.tier || 'D';
const score = lead.score || 0;
const email = lead.email || '';
const gargalos = lead.gargalos || '';
const gargaloArr = typeof gargalos === 'string' ? gargalos.split(', ') : (Array.isArray(gargalos) ? gargalos : []);
const gargalo_principal = gargaloArr[0] ? gargaloArr[0].split(' — ')[0] : 'processos manuais';
const gargalo_2 = gargaloArr[1] ? gargaloArr[1].split(' — ')[0] : gargalo_principal;
const prioridade = lead.prioridade || 'Eliminar processos manuais';

// Hours calculation
const horasMap = { '~20h/mês': 20, '~40-60h/mês': 50, '~65-160h/mês': 112, '+160h/mês': 180 };
const tempo_horas_mes = lead.tempo_horas_mes || '~20h/mês';
const horas_mes_num = horasMap[tempo_horas_mes] || 20;
const horas_semana_num = Math.round(horas_mes_num / 4);
const horas_semana_labels = { 20: '~3h', 50: '~10h', 112: '~28h', 180: '50h+' };
const horas_semana = horas_semana_labels[horas_mes_num] || '~' + horas_semana_num + 'h';
const pct_funcionario = Math.round((horas_mes_num / 160) * 100);

// ROI calculation
const sectorCost = {
  'Varejo/E-commerce': 32, 'Indústria/Manufatura': 41,
  'Logística/Distribuição': 35, 'Saúde/Clínicas': 45,
  'Financeiro/Contabilidade': 54, 'SaaS/Tecnologia': 63,
  'Serviços em geral': 36, 'Outro': 38
};
const hourlyCost = sectorCost[setor] || 38;
const roi_mensal_num = horas_mes_num * hourlyCost;
const roi_anual_num = roi_mensal_num * 12;
const fmtBRL = (v) => 'R$ ' + v.toLocaleString('pt-BR');

const whatsapp_msg = encodeURIComponent(
  `Oi! Acabei de fazer o diagnóstico da Gradios. Sou ${cargo} de uma empresa de ${setor} com ${lead.tamanho || 'vários'} funcionários. Nosso maior gargalo é ${gargalo_principal.toLowerCase()} e perdemos cerca de ${horas_semana} horas por semana com retrabalho manual. Recebi resultado ${tier} e quero entender como resolver isso.`
);

return [{
  json: {
    email,
    nome,
    empresa,
    setor,
    cargo,
    tier,
    score,
    gargalo_principal,
    gargalo_2,
    horas_semana,
    horas_mes: horas_mes_num + 'h',
    horas_mes_num,
    pct_funcionario: pct_funcionario.toString(),
    roi_mensal: fmtBRL(roi_mensal_num),
    roi_anual: fmtBRL(roi_anual_num),
    prioridade,
    diagnostico_url: 'https://gradios.co/diagnostico',
    whatsapp_url: 'https://wa.me/5543988372540?text=' + whatsapp_msg
  }
}];

// Email 1 templates — select by tier
const d = $input.first().json;
const tier = d.tier;

const subjects = {
  A: 'Seu diagnóstico chegou — e o resultado é sério',
  B: `Diagnóstico da ${d.empresa} — veja o que encontramos`,
  C: 'Seu diagnóstico de automação está aqui',
  D: `Seu diagnóstico está pronto, ${d.nome}`
};

const bodies = {
  A: `${d.nome},

Cruzamos as respostas da ${d.empresa} e o cenário é claro.

Vocês perdem ${d.horas_semana} por semana com processos manuais. Isso é ${d.horas_mes} por mês — equivalente a ${d.pct_funcionario}% de um funcionário inteiro só em retrabalho.

